query:
SELECT @camilaCompanyId := companyId FROM users WHERE name = 'Camila Pires' LIMIT 1;
UPDATE users SET companyId = @camilaCompanyId WHERE role = 'broker' AND (companyId IS NULL OR companyId != @camilaCompanyId);
SELECT COUNT(*) as updated_brokers FROM users WHERE role = 'broker' AND companyId = @camilaCompanyId;

